-- ================================================================
-- ILET Security Audit — RLS & Database Security Patches
-- Run this in Supabase Dashboard > SQL Editor
-- Generated by Security Audit: 2026-06-16
-- ================================================================

-- ================================================================
-- 1. APPLICATIONS TABLE — Missing RLS (VULN-10)
-- ================================================================
ALTER TABLE public.applications ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Admins can read all applications" ON public.applications;
DROP POLICY IF EXISTS "Anyone can submit application" ON public.applications;
DROP POLICY IF EXISTS "Admins can update application status" ON public.applications;

-- Anyone can submit an application (public endpoint)
CREATE POLICY "Anyone can submit application"
    ON public.applications FOR INSERT
    TO public
    WITH CHECK (true);

-- Only admins can read applications (contains PII: name, email, whatsapp, id card URL)
CREATE POLICY "Admins can read all applications"
    ON public.applications FOR SELECT
    TO authenticated
    USING (get_my_role() = 'admin');

-- Only admins can update application status
CREATE POLICY "Admins can update application status"
    ON public.applications FOR UPDATE
    TO authenticated
    USING (get_my_role() = 'admin');

-- ================================================================
-- 2. FEEDBACK TABLE — Missing RLS (VULN-10)
-- ================================================================
ALTER TABLE public.feedback ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Anyone can submit feedback" ON public.feedback;
DROP POLICY IF EXISTS "Admins and moderators can read feedback" ON public.feedback;

-- Anyone can submit feedback (public form)
CREATE POLICY "Anyone can submit feedback"
    ON public.feedback FOR INSERT
    TO public
    WITH CHECK (true);

-- Only admins/moderators can read submitted feedback
CREATE POLICY "Admins and moderators can read feedback"
    ON public.feedback FOR SELECT
    TO authenticated
    USING (get_my_role() IN ('admin', 'moderator'));

-- ================================================================
-- 3. AUDIT LOGS TABLE — Missing RLS (VULN-10)
-- ================================================================
ALTER TABLE public.audit_logs ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Admins can read audit logs" ON public.audit_logs;

-- Only admins can read audit logs
CREATE POLICY "Admins can read audit logs"
    ON public.audit_logs FOR SELECT
    TO authenticated
    USING (get_my_role() = 'admin');

-- No INSERT policy — admin server actions use service_role client which bypasses RLS.
-- This prevents any authenticated user from writing arbitrary audit log entries.

-- ================================================================
-- 4. USERS TABLE — Prevent self role escalation (privilege escalation hardening)
-- ================================================================
-- Drop and recreate the update policy to prevent users from changing their own role
DROP POLICY IF EXISTS "Users can update own profile" ON public.users;

CREATE POLICY "Users can update own profile"
    ON public.users FOR UPDATE
    TO authenticated
    USING (auth.uid() = id)
    WITH CHECK (
        auth.uid() = id
        -- Prevent role self-escalation: the role column value cannot change
        -- via this policy (service_role client bypasses this for admin operations)
        AND role = (SELECT role FROM public.users WHERE id = auth.uid())
    );

-- ================================================================
-- 5. QUESTIONS TABLE — Patch soft-delete and missing update policies
-- ================================================================

-- Patch the public read policy to exclude soft-deleted questions
DROP POLICY IF EXISTS "Public read approved questions" ON public.questions;

CREATE POLICY "Public read approved questions"
    ON public.questions FOR SELECT
    TO public
    USING (status = 'approved' AND (deleted_at IS NULL));

-- Moderators and admins can update question status (approve/reject)
DROP POLICY IF EXISTS "Moderators can update question status" ON public.questions;

CREATE POLICY "Moderators can update question status"
    ON public.questions FOR UPDATE
    TO authenticated
    USING (get_my_role() IN ('admin', 'moderator'))
    WITH CHECK (get_my_role() IN ('admin', 'moderator'));

-- ================================================================
-- 6. VERIFY RLS IS ENABLED ON ALL TABLES
-- ================================================================
-- Run this after applying the patch to confirm RLS is enabled:
SELECT
    n.nspname                  AS schema,
    c.relname                  AS table_name,
    c.relrowsecurity           AS rls_enabled,
    c.relforcerowsecurity      AS rls_forced
FROM pg_class c
JOIN pg_namespace n ON n.oid = c.relnamespace
WHERE n.nspname = 'public'
  AND c.relkind = 'r'
ORDER BY c.relname;
